GwImmersiveQuestingDebugFrameMixin = {}

function GwImmersiveQuestingDebugFrameMixin:UiScaleChanged()
    local sf = GW.settings.immersiveQuesting.scale
    self:SetScale(UIParent:GetScale() * sf)
    self.defer_ui_change = false
end

function GwImmersiveQuestingDebugFrameMixin:OnEvent(event, ...)
    if event == "UI_SCALE_CHANGED" then
        if not self.defer_ui_change then
            -- pause one frame for cvars but don't queue multiple of these
            self.defer_ui_change = true
            C_Timer.After(0, function() self:UiScaleChanged() end)
        end
    end
end

local function grid_OnClick(self)
    local df = self:GetParent():GetParent()
    local bg = GwImmersiveQuestFrame.container.mapBG
    if df.bgTex ~= 0 then
        bg:SetTexture(df.bgTex)
        df.bgTex = 0
    else
        df.bgTex = bg:GetTexture()
        bg:SetTexture("Interface/AddOns/GW2_UI/textures/questview/backgrounds/misc/grid")
    end
end

local function feet_OnClick(self)
    local b = GwImmersiveQuestFrame.container.dialog.blackout_feet
    local cb = GwImmersiveQuestFrame.container.blackout_head
    if b:IsShown() then
        b:Hide()
        cb:Hide()
    else
        b:Show()
        cb:Show()
    end
end

local function face_OnClick(self)
    local pm = GwImmersiveQuestFrame.container.playerModel
    local gm = GwImmersiveQuestFrame.container.giverModel
    if self.old_facing then
        pm:SetFacing(self.old_facing)
        self.old_facing = nil
        pm:SetAnimation(0)
        gm:SetAnimation(0)
    else
        self.old_facing = pm:GetFacing()
        pm:SetFacing(gm:GetFacing())
        pm:FreezeAnimation(0, 0, 0)
        gm:FreezeAnimation(0, 0, 0)
    end
end

local function kit_OnClick()
    local pm = GwImmersiveQuestFrame.container.playerModel

    pm:SetAction("read")
    --[[
    if pm.freeze_frame then
        -- 128
        pm:FreezeAnimation(89, 0, pm.freeze_frame)
        pm.freeze_frame = pm.freeze_frame + 20
    else
        --pm:SetAnimation(128)
        pm:ApplySpellVisualKit(230853, false)
        pm.freeze_frame = 20
        kit_OnClick()
    end
    --]]
    --[[
    if pm.applied_kit then
        pm.applied_kit = pm.applied_kit + 1
    else
        pm.applied_kit = 1
        pm:SetAnimation(520)
    end
    local kit_num = OPEN_KITS[pm.applied_kit]
    Debug("apply kit", pm.applied_kit, "of", #OPEN_KITS, ":", kit_num)
    pm:ApplySpellVisualKit(0, true)
    pm:ApplySpellVisualKit(kit_num, false)
    --]]
end

local function set_unit(cid, did)
    local gm = GwImmersiveQuestFrame.container.giverModel
    gm:SetQuestUnit(cid, did)
    gm:Show()
end

local function reset_OnClick(self)
    local df = self:GetParent():GetParent()
    local bg = GwImmersiveQuestFrame.container.mapBG
    local b = GwImmersiveQuestFrame.container.dialog.blackout_feet
    local cb = GwImmersiveQuestFrame.container.blackout_head
    local pm = GwImmersiveQuestFrame.container.playerModel
    local gm = GwImmersiveQuestFrame.container.giverModel
    if df.bgTex ~= 0 then
        bg:SetTexture(df.bgTex)
        df.bgTex = 0
    end
    if not b:IsShown() then
        b:Show()
        cb:Show()
    end
    if self.old_facing then
        pm:SetFacing(self.old_facing)
        self.old_facing = nil
    else
        pm:SetFacing(0.5)
    end
    pm:SetAnimation(0)
    gm:Hide()
    C_Timer.After(0, set_unit)
end

local function show_creature(cid, did)
    local gm = GwImmersiveQuestFrame.container.giverModel
    gm:Hide()
    C_Timer.After(0, function () set_unit(cid, did) end)
end

