function GW.LoadImmersiveQuestionDebugFrame()
    local frame = CreateFrame("Frame", "GwImmersiveQuestDebugFrame", nil, "GwImmersiveQuestingDebugFrameTemplate")
    frame.bgTex = 0
    frame.border:SetTextureSliceMargins(32, 32, 32, 32)
    frame.border:SetTextureSliceMode(Enum.UITextureSliceMode.Stretched)

    frame.container.gridButton:SetScript("OnClick", grid_OnClick)
    frame.container.feetButton:SetScript("OnClick", feet_OnClick)
    frame.container.faceButton:SetScript("OnClick", face_OnClick)
    frame.container.resetButton:SetScript("OnClick", reset_OnClick)
    frame.container.kitButton:SetScript("OnClick", kit_OnClick)

    local y_off = -64
    for i = 1, #model_buttons do
        local btn_def = model_buttons[i]
        local mod_idx = (i - 1) % 4
        local btn = CreateFrame("Button", nil, frame.container, "GwImmersiveQuestingDebugButtonTemplate")
        btn:SetText(btn_def[1])
        btn:SetScript("OnClick", function () show_creature(btn_def[2], btn_def[3]) end)
        if mod_idx == 0 then
            btn:SetPoint("TOPLEFT", frame.container, "TOPLEFT", 0, y_off)
        elseif mod_idx == 1 then
            btn:SetPoint("TOP", frame.container, "TOP", -37, y_off)
        elseif mod_idx == 2 then
            btn:SetPoint("TOP", frame.container, "TOP", 37, y_off)
        else
            btn:SetPoint("TOPRIGHT", frame.container, "TOPRIGHT", 0, y_off)
            y_off = y_off - 32
        end
    end

    if not frame.defer_ui_change then
        -- pause one frame for cvars but don't queue multiple of these
        frame.defer_ui_change = true
        C_Timer.After(0, function() frame:UiScaleChanged() end)
    end

    frame:SetScript("OnEvent", frame.OnEvent)
    frame:RegisterEvent("UI_SCALE_CHANGED")
end
